+    let source_id_hash = crc32fast::hash(packet.payload.provenance.source_id.as_bytes());
+    packet
+        .projections
+        .semantic
+        .message_indices
+        .iter()
+        .filter_map(|message_index| {
+            packet
+                .payload
+                .messages
+                .get(*message_index)
+                .and_then(|message| {
+                    embedding_input_from_packet_message(
+                        row.conversation_id,
+                        agent_id,
+                        workspace_id,
+                        source_id_hash,
+                        message,
+                    )
+                })
+        })
+        .collect()
